const aiOutput = $input.first().json;
let parsed;
try {
  let raw = '';
  if (aiOutput.content && Array.isArray(aiOutput.content)) {
    for (const block of aiOutput.content) {
      if (block.type === 'text') {
        raw += block.text;
      }
    }
  } else if (typeof aiOutput.output === 'string') {
    raw = aiOutput.output;
  } else {
    raw = JSON.stringify(aiOutput);
  }
  const jsonMatch = raw.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('JSON array not found in output');
  }
} catch(e) {
  return [{ json: { error: 'Failed to parse Director AI output: ' + e.message, raw: JSON.stringify(aiOutput).substring(0, 500) } }];
}

const staticData = $getWorkflowStaticData('global');
staticData.director_segments = parsed;
staticData.total_segments = parsed.length;
staticData.completed_segments = 0;
staticData.all_results = [];

const results = [];
for (const seg of parsed) {
  results.push({
    json: {
      timeline_id: seg.timeline_id,
      section: seg.section || '',
      segment_type: seg.segment_type || 'TALKING',
      time_range: seg.time_range || '',
      tts_text: seg.tts_text || '',
      tts_emotion: seg.tts_emotion || '',
      avatar_prompt: seg.avatar_prompt || '',
      broll_prompt: seg.broll_prompt || '',
      interaction_prompt: seg.interaction_prompt || '',
      broll_name: seg.broll_name || '',
      brand: $('기존 이미지 세팅').first().json.brand || '',
      product: $('기존 이미지 세팅').first().json.product || '',
      price: $('기존 이미지 세팅').first().json.price || '',
      image_main_url: $('기존 이미지 세팅').first().json.image_main_url || '',
      image_sub_url: $('기존 이미지 세팅').first().json.image_sub_url || '',
      category: $('기존 이미지 세팅').first().json.category || '',
      video_style: $('기존 이미지 세팅').first().json.video_style || '',
      bgm_mood: $('기존 이미지 세팅').first().json.bgm_mood || '',
      target_duration: $('기존 이미지 세팅').first().json.target_duration || 30
    }
  });
}
return results;

const items = $input.all();
const ttsItems = items.filter(item => item.json.segment_type === 'TALKING' && item.json.tts_text && item.json.tts_text.trim() !== '');
return ttsItems;

const result = $input.first().json;
const loopItem = $('TTS 순차 루프').first().json;

let audioUrl = '';
if (result.result && result.result.audio_download_url) {
  audioUrl = result.result.audio_download_url;
} else if (result.audio_download_url) {
  audioUrl = result.audio_download_url;
} else if (result.result && result.result.url) {
  audioUrl = result.result.url;
} else if (result.url) {
  audioUrl = result.url;
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.tts_audio_map) {
  staticData.tts_audio_map = {};
}
staticData.tts_audio_map[loopItem.timeline_id] = audioUrl;

return [{
  json: {
    timeline_id: loopItem.timeline_id,
    audio_url: audioUrl,
    segment_type: loopItem.segment_type,
    tts_text: loopItem.tts_text
  }
}];

